import numpy as np
import matplotlib.pyplot as plt

# Time domain signal parameters
fs = 1000  # Sampling frequency (Hz)
T = 1.0    # Duration (seconds)
t = np.linspace(0, T, int(fs * T), endpoint=False)

# Compose a signal from multiple frequency components
f1, A1 = 5, 1.0    # 5 Hz, amplitude 1.0
f2, A2 = 20, 0.5   # 20 Hz, amplitude 0.5
f3, A3 = 50, 0.3   # 50 Hz, amplitude 0.3

signal = (A1 * np.sin(2 * np.pi * f1 * t) +
          A2 * np.sin(2 * np.pi * f2 * t) +
          A3 * np.sin(2 * np.pi * f3 * t))

# Individual components for illustration
comp1 = A1 * np.sin(2 * np.pi * f1 * t)
comp2 = A2 * np.sin(2 * np.pi * f2 * t)
comp3 = A3 * np.sin(2 * np.pi * f3 * t)

# Fourier Transform
N = len(signal)
fft_vals = np.fft.fft(signal)
fft_freq = np.fft.fftfreq(N, d=1.0/fs)

# Only positive frequencies
pos_mask = fft_freq >= 0
fft_freq_pos = fft_freq[pos_mask]
fft_magnitude = (2.0 / N) * np.abs(fft_vals[pos_mask])

# Limit frequency axis for clarity
freq_limit = 80  # Hz

# --- Plotting ---
fig, axes = plt.subplots(3, 2, figsize=(14, 10))
plt.suptitle("Fourier Transform: Time Domain and Frequency Domain Decomposition", y=0.98, fontsize=13, fontweight='bold')

# Color palette
colors = ['#1f77b4', '#ff7f0e', '#2ca02c']

# ---- Left column: Time domain ----

# Row 0: Composite signal
ax = axes[0, 0]
ax.plot(t[:300], signal[:300], color='black', linewidth=1.2, label='Composite signal')
ax.set_title("Composite Time Domain Signal", fontsize=11)
ax.set_xlabel("Time (s)")
ax.set_ylabel("Amplitude")
ax.legend(loc='upper right', fontsize=9)
ax.grid(True, alpha=0.3)
ax.set_xlim(0, t[299])

# Row 1: Individual components (time)
ax = axes[1, 0]
ax.plot(t[:300], comp1[:300], color=colors[0], linewidth=1.2, label=f'{f1} Hz  (A={A1})')
ax.plot(t[:300], comp2[:300], color=colors[1], linewidth=1.2, label=f'{f2} Hz  (A={A2})')
ax.plot(t[:300], comp3[:300], color=colors[2], linewidth=1.2, label=f'{f3} Hz  (A={A3})')
ax.set_title("Individual Sinusoidal Components (Time Domain)", fontsize=11)
ax.set_xlabel("Time (s)")
ax.set_ylabel("Amplitude")
ax.legend(loc='upper right', fontsize=9)
ax.grid(True, alpha=0.3)
ax.set_xlim(0, t[299])

# Row 2: Phase information
phase = np.angle(fft_vals[pos_mask])
ax = axes[2, 0]
freq_mask = fft_freq_pos <= freq_limit
ax.stem(fft_freq_pos[freq_mask], phase[freq_mask],
        linefmt='grey', markerfmt='D', basefmt='k-')
ax.set_title("Phase Spectrum", fontsize=11)
ax.set_xlabel("Frequency (Hz)")
ax.set_ylabel("Phase (radians)")
ax.set_xlim(0, freq_limit)
ax.axhline(0, color='black', linewidth=0.8)
ax.grid(True, alpha=0.3)

# ---- Right column: Frequency domain ----

# Row 0: Full magnitude spectrum
ax = axes[0, 1]
freq_mask = fft_freq_pos <= freq_limit
ax.plot(fft_freq_pos[freq_mask], fft_magnitude[freq_mask], color='black', linewidth=1.2)
ax.fill_between(fft_freq_pos[freq_mask], fft_magnitude[freq_mask], alpha=0.15, color='black')
ax.set_title("Frequency Domain (Magnitude Spectrum)", fontsize=11)
ax.set_xlabel("Frequency (Hz)")
ax.set_ylabel("Magnitude")
ax.grid(True, alpha=0.3)
ax.set_xlim(0, freq_limit)

# Annotate peaks
for f, A, c in zip([f1, f2, f3], [A1, A2, A3], colors):
    ax.annotate(f'{f} Hz\nA={A}',
                xy=(f, A), xytext=(f + 3, A + 0.05),
                fontsize=8, color=c,
                arrowprops=dict(arrowstyle='->', color=c, lw=1.2))

# Row 1: Stem plot of frequency components
ax = axes[1, 1]
ax.stem(fft_freq_pos[freq_mask], fft_magnitude[freq_mask],
        linefmt='C0-', markerfmt='C0o', basefmt='k-')
ax.set_title("Frequency Spectrum (Stem Plot)", fontsize=11)
ax.set_xlabel("Frequency (Hz)")
ax.set_ylabel("Magnitude")
ax.set_xlim(0, freq_limit)
ax.grid(True, alpha=0.3)

# Highlight the three main peaks
for f, A, c in zip([f1, f2, f3], [A1, A2, A3], colors):
    ax.axvline(x=f, color=c, linestyle='--', linewidth=1.2, alpha=0.7, label=f'{f} Hz')
ax.legend(loc='upper right', fontsize=9)

# Row 2: Power spectral density
power = fft_magnitude[freq_mask] ** 2
ax = axes[2, 1]
ax.bar(fft_freq_pos[freq_mask], power,
       width=0.5, color='steelblue', alpha=0.7, label='Power')
ax.set_title("Power Spectrum", fontsize=11)
ax.set_xlabel("Frequency (Hz)")
ax.set_ylabel("Power (amplitude^2)")
ax.set_xlim(0, freq_limit)
ax.grid(True, alpha=0.3)
ax.legend(loc='upper right', fontsize=9)

plt.tight_layout()
plt.savefig("fourier_transform_analysis.png", dpi=150, bbox_inches='tight')
print("Plot saved as fourier_transform_analysis.png")
plt.show()

print("Signal composed of:")
print(f"  Component 1: {f1} Hz, Amplitude = {A1}")
print(f"  Component 2: {f2} Hz, Amplitude = {A2}")
print(f"  Component 3: {f3} Hz, Amplitude = {A3}")
print(f"Sampling frequency: {fs} Hz, Duration: {T} s, N samples: {N}")
print(f"FFT frequency resolution: {fs/N:.2f} Hz")
print("Fourier Transform analysis complete.")